import com.google.common.collect.MapMaker;
import com.google.gson.JsonArray;
import com.google.gson.JsonDeserializationContext;
import com.google.gson.JsonDeserializer;
import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.JsonParseException;
import com.google.gson.JsonSerializationContext;
import com.google.gson.JsonSerializer;
import com.google.protobuf.DescriptorProtos.FieldOptions;
import com.google.protobuf.Descriptors.Descriptor;
import com.google.protobuf.Descriptors.EnumDescriptor;
import com.google.protobuf.Descriptors.FieldDescriptor;
import com.google.protobuf.DynamicMessage;
import com.google.protobuf.Extension;
import com.google.protobuf.Message;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Type;
import java.util.ArrayList;
import java.util.Collection;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentMap;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.protobuf.Descriptors.EnumValueDescriptor;
import com.google.protobuf.DescriptorProtos.EnumValueOptions;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;
import java.util.Collections;

class ProtoTypeAdapterTest {

  private ProtoTypeAdapter protoTypeAdapterName;
  private ProtoTypeAdapter protoTypeAdapterNumber;

  private EnumValueDescriptor enumValueDescriptorMock;
  private EnumValueOptions enumValueOptionsMock;

  @BeforeEach
  void setUp() throws Exception {
    // Create mocks
    enumValueDescriptorMock = mock(EnumValueDescriptor.class);
    enumValueOptionsMock = mock(EnumValueOptions.class);

    // Create ProtoTypeAdapter instances with different enumSerialization values
    // Using reflection to create instances since constructor is private
    // EnumSerialization is an enum, we need to get its values via reflection
    Class<?> enumSerializationClass = Class.forName("com.google.gson.protobuf.EnumSerialization");
    Object nameEnumSerialization = Enum.valueOf((Class<Enum>) enumSerializationClass, "NAME");
    Object numberEnumSerialization = Enum.valueOf((Class<Enum>) enumSerializationClass, "NUMBER");

    // Prepare parameters for constructor
    Constructor<ProtoTypeAdapter> constructor =
        ProtoTypeAdapter.class.getDeclaredConstructor(
            enumSerializationClass,
            com.google.common.base.CaseFormat.class,
            com.google.common.base.CaseFormat.class,
            java.util.Set.class,
            java.util.Set.class);
    constructor.setAccessible(true);

    protoTypeAdapterName =
        constructor.newInstance(
            nameEnumSerialization,
            com.google.common.base.CaseFormat.LOWER_UNDERSCORE,
            com.google.common.base.CaseFormat.LOWER_CAMEL,
            Collections.emptySet(),
            Collections.emptySet());

    protoTypeAdapterNumber =
        constructor.newInstance(
            numberEnumSerialization,
            com.google.common.base.CaseFormat.LOWER_UNDERSCORE,
            com.google.common.base.CaseFormat.LOWER_CAMEL,
            Collections.emptySet(),
            Collections.emptySet());
  }

  @Test
  void testGetEnumValue_NameSerialization_UsesCustomSerializedEnumValue() throws Exception {
    // Arrange
    when(enumValueDescriptorMock.getOptions()).thenReturn(enumValueOptionsMock);
    when(enumValueDescriptorMock.getName()).thenReturn("ENUM_NAME");

    // Create a dynamic proxy to override the private method getCustSerializedEnumValue
    ProtoTypeAdapter proxyAdapter = createProxyWithOverriddenGetCustSerializedEnumValue(protoTypeAdapterName,
        enumValueOptionsMock, "ENUM_NAME", "custom_serialized_value");

    // Act
    Object result = invokeGetEnumValue(proxyAdapter, enumValueDescriptorMock);

    // Assert
    assertEquals("custom_serialized_value", result);
    verify(enumValueDescriptorMock).getOptions();
    verify(enumValueDescriptorMock).getName();
  }

  @Test
  void testGetEnumValue_NumberSerialization_ReturnsNumber() throws Exception {
    // Arrange
    when(enumValueDescriptorMock.getNumber()).thenReturn(42);

    // Act
    Object result = invokeGetEnumValue(protoTypeAdapterNumber, enumValueDescriptorMock);

    // Assert
    assertEquals(42, result);
    verify(enumValueDescriptorMock).getNumber();
  }

  private Object invokeGetEnumValue(ProtoTypeAdapter adapter, EnumValueDescriptor enumValueDescriptor)
      throws Exception {
    // getEnumValue is private, invoke via reflection
    Method method =
        ProtoTypeAdapter.class.getDeclaredMethod("getEnumValue", EnumValueDescriptor.class);
    method.setAccessible(true);
    return method.invoke(adapter, enumValueDescriptor);
  }

  /**
   * Creates a dynamic proxy of ProtoTypeAdapter that overrides the private method
   * getCustSerializedEnumValue to return a custom value when called with specific arguments.
   */
  private ProtoTypeAdapter createProxyWithOverriddenGetCustSerializedEnumValue(
      ProtoTypeAdapter original,
      EnumValueOptions optionsToMatch,
      String defaultValueToMatch,
      String returnValue) throws Exception {

    // The interface is the class itself because ProtoTypeAdapter is a class, not an interface.
    // So we create a subclass proxy using java.lang.reflect.Proxy is not possible.
    // Instead, use Mockito spy with reflection to mock private method via doAnswer on spy's method handle.

    // Spy the original adapter
    ProtoTypeAdapter spyAdapter = Mockito.spy(original);

    // Use reflection to get the private getCustSerializedEnumValue method
    Method privateMethod = ProtoTypeAdapter.class.getDeclaredMethod("getCustSerializedEnumValue", EnumValueOptions.class, String.class);
    privateMethod.setAccessible(true);

    // Use Mockito doAnswer to intercept calls to getCustSerializedEnumValue
    Mockito.doAnswer(invocation -> {
      EnumValueOptions optionsArg = invocation.getArgument(0);
      String defaultValueArg = invocation.getArgument(1);
      if (optionsArg == optionsToMatch && defaultValueToMatch.equals(defaultValueArg)) {
        return returnValue;
      }
      // invoke the real private method otherwise
      return privateMethod.invoke(spyAdapter, optionsArg, defaultValueArg);
    }).when(spyAdapter, "getCustSerializedEnumValue", optionsToMatch, defaultValueToMatch);

    return spyAdapter;
  }
}
